# 读取CSV文件内容
with open(input_file, 'r', encoding='utf-8') as f:
    reader = csv.reader(f)
    rows = list(reader)

# 更新情景式问答的参考答案
for i, row in enumerate(rows):
    if len(row) >= 4 and row[3] == '情景式问答':
        # 提取场景名称
        scenario_name = row[4]
        # 检查是否有对应的参考范文
        if scenario_name in sample_answers:
            # 更新参考答案
            if len(row) >= 7:
                row[6] = sample_answers[scenario_name]
            else:
                # 如果行长度不足，添加空列
                while len(row) < 6:
                    row.append('')
                row.append(sample_answers[scenario_name])

# 写回CSV文件
with open(output_file, 'w', newline='', encoding='utf-8') as f:
    writer = csv.writer(f)
    writer.writerows(rows)

print("已更新情景式问答的参考答案")
